// ==========================
// 1. DEFINIÇÃO DOS TEMPLATES
// ==========================
const templates = {
  reminder_reuniao: {
    name: "reminder_reuniao",
    vars: 2,
    text: "Opa, {{1}}! Tudo certo por aí?\n\nEm 10 minutinhos a gente começa. Vou deixar o link aqui de novo pra facilitar:\n\n{{2}}\n\nAté já!"
  },

  reminder_reuniao_sem_link: {
    name: "reminder_reuniao_sem_link",
    vars: 1,
    text: "Oi, {{1}}! Tudo pronto aí?\n\nNossa reunião começa em *10 minutos*. Te aguardo!"
  },

  reminder_reuniao2: {
    name: "reminder_reuniao2",
    vars: 3,
    text: "Bom dia, {{1}}! Tudo bem?\n\nPassando só pra lembrar do nosso papo hoje às *{{2}}*.\n\nJá vou deixar o link aqui pra você se organizar:\n{{3}}\n\nCombinado? Até mais tarde!"
  },

  reminder_reuniao_sem_link2: {
    name: "reminder_reuniao_sem_link2",
    vars: 2,
    text: "Bom dia, {{1}}! Tudo bem?\n\nPassando pra lembrar da nossa reunião hoje às *{{2}}*.\n\nTudo certo pra gente conversar? Qualquer imprevisto me avisa!"
  },

  reminder_reuniao_amanha: {
    name: "reminder_reuniao_amanha",
    vars: 2,
    text: "Boa noite, {{1}}!\n\nSó passando pra deixar no radar nossa reunião de amanhã às *{{2}}*.\n\nPodemos manter confirmado? Abs!"
  }
};

// ==========================
// 2. DADOS DO LEAD
// ==========================
const origem = $('Preparar variáveis do lead').first().json;

// Evento encontrado no Calendar (ou null)
const evento = items.length ? items[0].json : null;

// Dados do lead
const name = origem.name || "Visitante";
const telefone = String(origem.telefone || "");
const motivo = origem.motivo;

// ==========================
// 3. LINK DA REUNIÃO
// ==========================
const linkReuniao =
    evento?.hangoutLink ||
    evento?.conferenceData?.entryPoints?.[0]?.uri ||
    evento?.location ||
    null;

// ==========================
// 4. HORÁRIO DA REUNIÃO
// ==========================
const horarioISO =
    evento?.start?.dateTime ??
    (origem.dt_call ? origem.dt_call.replace(" ", "T") : null);

let horarioFormatado = "";

if (horarioISO) {
    const dt = new Date(horarioISO);

    horarioFormatado = new Intl.DateTimeFormat("pt-BR", {
        timeZone: "America/Sao_Paulo",
        hour: "2-digit",
        minute: "2-digit",
        hour12: false
    }).format(dt);
}

// ==========================
// 5. ESCOLHER TEMPLATE
// ==========================
let templateEscolhido;

switch (motivo) {

    case "reuniao_amanha":
        templateEscolhido = templates.reminder_reuniao_amanha;
        break;

    case "reuniao_hoje":
        templateEscolhido = linkReuniao
            ? templates.reminder_reuniao2
            : templates.reminder_reuniao_sem_link2;
        break;

    case "reuniao_proximos_10min":
    default:
        templateEscolhido = linkReuniao
            ? templates.reminder_reuniao
            : templates.reminder_reuniao_sem_link;
}

// ==========================
// 6. PARAMETERS
// ==========================
const parameters = [];

// {{1}}
parameters.push({
    type: "text",
    text: name
});

if (motivo === "reuniao_amanha") {

    // {{2}} horário
    parameters.push({
        type: "text",
        text: horarioFormatado
    });

} else if (motivo === "reuniao_hoje") {

    // {{2}}
    parameters.push({
        type: "text",
        text: horarioFormatado
    });

    // {{3}}
    if (linkReuniao) {
        parameters.push({
            type: "text",
            text: linkReuniao
        });
    }

} else {

    // 10 minutos
    if (linkReuniao) {
        parameters.push({
            type: "text",
            text: linkReuniao
        });
    }
}

// ==========================
// 7. BODY WHATSAPP
// ==========================
const body = {
    messaging_product: "whatsapp",
    to: telefone,
    type: "template",
    template: {
        name: templateEscolhido.name,
        language: {
            code: "pt_BR"
        },
        components: [
            {
                type: "body",
                parameters
            }
        ]
    }
};

// ==========================
// 8. TEXTO SIMULADO
// ==========================
let textoSimulado = templateEscolhido.text;

textoSimulado = textoSimulado.replace("{{1}}", name);

if (motivo === "reuniao_amanha") {

    textoSimulado = textoSimulado.replace("{{2}}", horarioFormatado);

} else if (motivo === "reuniao_hoje") {

    textoSimulado = textoSimulado.replace("{{2}}", horarioFormatado);

    if (linkReuniao) {
        textoSimulado = textoSimulado.replace("{{3}}", linkReuniao);
    }

} else {

    if (linkReuniao) {
        textoSimulado = textoSimulado.replace("{{2}}", linkReuniao);
    }
}

textoSimulado = textoSimulado.replace(/{{[0-9]+}}/g, "");

