// 9. REDIS CHAT MEMORY
// ==========================
const redisMemoryMessage = JSON.stringify({
    type: "ai",
    data: {
        content: textoSimulado,
        tool_calls: [],
        invalid_tool_calls: [],
        additional_kwargs: {},
        response_metadata: {},
    },
});

// ==========================
// RETORNO
// ==========================
return [{
