function ajustarTelefone(raw) {
  if (!raw) return null;
  let t = raw.toString().replace(/\D/g, "");
  if (t.length === 11) t = "55" + t;
  if (t.length === 10) t = "55" + t;
  if (t.startsWith("55")) return t;
  if (t.startsWith("+")) return t.replace("+", "");
  return t;
}

// Converte "2026-07-22 09:30:00" -> Date, de forma segura (sem depender do parser nativo)
function parseDtCall(dtCallStr) {
  if (!dtCallStr) return null;
  const [dataPart, horaPart] = dtCallStr.split(" ");
  if (!dataPart) return null;
  const [ano, mes, dia] = dataPart.split("-").map(Number);
  const [h, m, s] = (horaPart || "00:00:00").split(":").map(Number);
  return new Date(ano, mes - 1, dia, h || 0, m || 0, s || 0);
}

// ========================================
// Identificar gatilho real (9h ou 10min)
// ========================================
