    if (dataReuniao === dataAmanha) {
      filtrados.push({
        json: {
          ...lead,
          telefonePadronizado: ajustarTelefone(telefone),
          motivo: "reuniao_amanha"
        }
      });
    }
  }
  return filtrados;
}

